var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그림자......?","JPN":"シャドウ……？","ENG":"Shadow?","TWN":"暗影？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"미, 미안하다. 잘 못 들었어. 방금 뭐라고 했지?","JPN":"す、すまない。よく聞こえなかった。今何と言った？","ENG":"S-sorry. I must have misheard you. What did you just say?","TWN":"抱、抱歉，我沒有聽清楚。妳剛才說什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네게 악의는 없는 것 같지만, 그렇다고 사실이 바뀌지는 않아.","JPN":"あなたに敵意はないようだけど、それでも事実は変わらないわ。","ENG":"You don't seem to have any malicious ulterior motives... but that doesn't change the fact.","TWN":"儘管妳沒有惡意，但事實卻不會改變。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대답해! 방금 날 뭐라고 불렀는지!","JPN":"答えろ！　今、私を何と呼んだ！","ENG":"Answer me! What did you just call me?","TWN":"回答我！妳剛才說我是什麼！"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그림자.","JPN":"シャドウ。","ENG":"A Shadow.","TWN":"暗影。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"넌...... 그저 자신이 류드밀라라고 착각하는 그림자형 침식체일 뿐이라는 말이다.","JPN":"あなたは……自分のことをリュドミラだと思い込んでる、\\nシャドウ型侵食体でしかないのよ。","ENG":"You're... just a Shadow-type C.O. who thinks she's Lyudmila.","TWN":"妳只是……妳只是把自己當成盧德米拉的暗影型侵蝕體。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하, 하하......","JPN":"ハ、ハハ……","ENG":"Hah... hah hah...","TWN":"哈、哈哈……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"농담 할 줄 모르는 건 예전과 똑같군.","JPN":"冗談が下手なのは昔と変わらないな。","ENG":"You've always had a terrible sense of humor.","TWN":"妳還是和以前一樣，這麼不會開玩笑。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"웃자고 한 말이라면 정말 재미없었어.","JPN":"笑わせたつもりなら、これは苦笑いだぞ。","ENG":"Sorry, but that joke was in poor taste.","TWN":"如果妳是在開玩笑的話，這一點都不好笑。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"말이 되는 소릴 해, 이수연!","JPN":"バカも休み休み言え、カナミ！","ENG":"Do you even know what you're saying, Sooyeon?","TWN":"妳覺得這可能嗎，李秀妍！"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"난 그날 이후로 수십 년 동안 혼자 계속 여기서 싸워 왔어!","JPN":"私はあの日以来、何十年にもわたって一人で戦ってきた！","ENG":"I've been fighting here for decades all by myself since that day!","TWN":"從那一天起，數十年以來，我一直留在這裡，一個人不斷地戰鬥！"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런데 이제 와서 나타난 이유가, 겨우 그런 말을 하기 위해서였나?","JPN":"今更現れたと思えば、そんな世迷言を言うために来たというのか？","ENG":"And you show up after all those years and tell me this?","TWN":"而妳如今出現在我面前，就是為了對我說這些？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......바로 그게 문제야.","JPN":"……そこがこの話の肝よ。","ENG":"That's exactly the problem here.","TWN":"……這就是問題所在了。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"인간은 이면세계에서 수십 년을 싸울 수 없어.","JPN":"人間は、裏世界で何十年も戦うことはできないわ。","ENG":"Humans can't fight for decades in the Counterside.","TWN":"人類是沒辦法在異界戰鬥數十年的。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"뭐......?","JPN":"何……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇지 않나? 정상적인 군대도 매일 격전에 치르면서 수십 년을 싸우면 보통은 미쳐 버릴 거야.","JPN":"だってそうでしょう？　正常に機能する軍隊でも\\n激戦の日々が数十年も続けば、普通は正気を保てないはずよ。","ENG":"Don't you get it? Even a well-trained army would go insane if they had to fight this hard every day for decades.","TWN":"難道不是嗎？就算是一個正常的軍隊，如果每天都在激戰，就這樣打了數十年，一定也會發瘋的。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 넌 멀쩡하게 살아서, 하루하루를 지치지도 않고 싸워 왔지.","JPN":"でもあなたは正気を保ったまま、\\n疲弊することなく戦いの日々を生き抜いてきたわ。","ENG":"But you've managed to not only stay alive, but fight every day without tiring.","TWN":"而妳卻能活得好好的，每天不知疲倦地戰鬥下去。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내가 포기하지 않은 게 침식체란 증거라고? 그렇게 말하고 싶은 건가?","JPN":"私が諦めていないことが侵食体である証拠だと？\\nそう言いたいのか？","ENG":"You're saying my relentlessness is the proof that I'm a C.O.? Is that what you're suggesting?","TWN":"我不放棄就是我是侵蝕體的證據？妳是想這樣說嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼 한 가지 물어 보지.","JPN":"それじゃあ、一つだけ聞かせて。","ENG":"Then let me ask you this.","TWN":"那我問妳一個問題。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대체 그 동안 뭘 먹고 살았어?","JPN":"今まで何を食べて生きてきたの？","ENG":"What have you been eating all those years?","TWN":"妳至今為止到底都吃了什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"뭘 먹고 살다니......","JPN":"何を食べて、って……","ENG":"What have I been eating?","TWN":"吃了什麼……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"당연히 다른 함선들에 실려 있던 물자로, 어떻게든......","JPN":"もちろん他の艦船に積んであった物資で何とか……","ENG":"Of course, I lived off of the supplies on the other ships...","TWN":"當然是其他艦船上的物資，我想盡辦法……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이면세계에서 관리국 전투식량의 표준 유통기한은 5년이야.","JPN":"裏世界における管理局戦闘糧食の標準的な賞味期限は、5年。","ENG":"In the Counterside, the standard shelf life for the Administration's field rations is 5 years.","TWN":"在異界，管理局戰鬥糧食的保存期限是5年。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"수십 년이면 썩어 문드러지기에 충분한 시간이지.","JPN":"数十年経ったなら、とっくに腐り果てている頃よ。","ENG":"A few decades are long enough to render the rations inedible.","TWN":"數十年的時間足夠讓食品全部腐壞。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"말해 봐. 최근에 식사를 한 기억이 있나?","JPN":"正直に言いなさい。最近食事を取った記憶はあるの？","ENG":"Tell me. When was the last time you ate something?","TWN":"告訴我，妳有最近一次吃飯的記憶嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"Well...","TWN":"這個……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그건...... 그러니까......","JPN":"それは……あぁ……","ENG":"I... Um...","TWN":"這……這個……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"말도 안 돼. 기억이...... 기억이 안 나......","JPN":"馬鹿な。何も……思い出せん……","ENG":"Impossible... I can't... I can’t remember...","TWN":"怎麼會這樣。我……我想不起來……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네 전대원들은 동결된 상태라 침식이 더디게 이루어지고 있었어.","JPN":"あなたの戦隊員たちは凍結状態なので、\\n侵食の進み具合は非常に遅いようだったわ。","ENG":"The rate of Corruption slowed down for your troops because they were in stasis.","TWN":"你的隊員處於凍結狀態，所以侵蝕進行得非常緩慢。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런데도 이미 돌이킬 수 없을 상태까지 진행됐지.","JPN":"それでも、今では取り返しがつかないほどまでに進んでいるの。","ENG":"But they've already become irreversibly corrupted.","TWN":"但他們也已經到了無法挽回的地步了。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 넌 이렇게 왕성하게 활동하면서도 침식 증후군 비슷한 증상도 보이지 않는군.","JPN":"なのにあなたはこんな旺盛に活動をしていながら、\\n侵食症候群らしい症状は少しも出てないわよね。","ENG":"And somehow you don't even show any signs of Corruption syndrome, even though you've been very active.","TWN":"相對的，妳的活動如此激烈，卻沒有出現侵蝕症候群之類的症狀。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아주 비정상적인 일이지.","JPN":"普通ではとてもあり得ないわ。","ENG":"It's very unusual.","TWN":"這太反常了。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래, 거기까지도 넘어가줄 수 있어.","JPN":"まあ、すべてが私の思い違いである可能性もゼロではないと思うわ。","ENG":"But let's say there's a slim chance that all of that doesn't mean anything.","TWN":"好吧，這些事我也忽略不去看吧。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"누가 알겠어. 세상에는 언제나 예외가 있는 법이니까.","JPN":"物事には必ず例外があり、この世には論理的に\\n説明できないこともあるのだから。","ENG":"You never know. There are always irregularities in the world.","TWN":"誰知道呢，畢竟這世界上總會有例外。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 무엇보다 확실한 증거가 거기에 있군.","JPN":"しかし残念ながら、歴然とした証拠がそこにあるの。","ENG":"But there's already a smoking gun right in front of you.","TWN":"但現在有個比什麼都要確切的證據。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네 팔을 봐.","JPN":"自分の腕を見てみなさい。","ENG":"Look at your arm.","TWN":"看看妳的手臂。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내 팔? 내 팔이 어떻다고...... ","JPN":"腕？　私の腕が何か…… ","ENG":"My arm? What about it... ","TWN":"我的手臂？我的手臂怎麼了……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 이건......","JPN":"待て、これは……","ENG":"Wait, this is...","TWN":"等等，這是……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"상당히 치열한 전투였나 봐. 왼팔이 완전히 날아가 버렸잖아.","JPN":"よほど熾烈な戦闘だったみたいね。\\n左腕が完全に吹っ飛んでるじゃないの。","ENG":"That must have been quite a fierce battle. They blew off your entire left arm.","TWN":"妳的戰鬥一定激烈吧，左手臂整個都沒了。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"상체도...... 어깨를 포함해서 4분의 1은 소실된 것 같고.","JPN":"上半身も……肩から4分の1は消失してるように見えるわね。","ENG":"And your torso too... You must have lost at least a quarter of your upper body, including your shoulder.","TWN":"上半身也是……包括肩膀的4分之1都消失了。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"재생 능력이 없는 한, 카운터라고 해도 살아나지 못할 부상이야.","JPN":"再生能力でもない限り、カウンターだとしても生存不可能な負傷よ。","ENG":"Unless you're capable of super healing, even a Counter wouldn't be able to survive such wounds.","TWN":"只要沒有再生能力，這種重傷就算是制裁者也不可能活下來。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 지금은 어때. 네 눈에 어떻게 보이나 말해 봐.","JPN":"なのに今どうなっているの？\\nあなたにはどう見えているか言ってみなさい。","ENG":"But look what's happening. Tell me what you see.","TWN":"但現在呢，妳自己的眼睛看看，然後回答我吧。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"회복...... 되고 있군......","JPN":"回復……しつつある……","ENG":"I'm... healing...","TWN":"正在……恢復……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내게...... 회복 능력 같은 건 없었을 텐데......","JPN":"私に……回復能力などなかったはず……","ENG":"But... healing wasn't one of my powers...","TWN":"我……應該沒有恢復能力的啊……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래. 지독한 침식파를 방출하면서 소실된 조직이 재생되고 있어.","JPN":"ええ。凄まじい侵食波を放ちながら、\\n消失した身体組織が再生しつつあるわね。","ENG":"That's right. Your tissues are regenerating, while emitting crazy amounts of Corruption rays.","TWN":"是的，妳釋放出強烈侵蝕波的同時，損壞的組織正在再生。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저 침식파 경보음, 네가 복귀한 뒤로 그치질 않아.","JPN":"あの侵食波警報音はあなたが帰還してから鳴り続けているわ。","ENG":"And you know what? That Corruption ray alarm has been going off ever since you got back here.","TWN":"那個侵蝕波警報，自從妳回來後就一直響個不停。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어때. 이래도 할 말이 남았어?","JPN":"まだ弁解の余地があるのかしら？","ENG":"Well? Do you still have trouble believing me?","TWN":"怎麼樣，還有什麼要說的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그럴 리가...... 그럴 리가 없잖아......","JPN":"そんなはずが……そんなはずがあるものか……","ENG":"It can’t be... There's no way...","TWN":"怎麼會……這怎麼可能……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내가 침식체라고? 대체 어떻게......?","JPN":"私が侵食体だと？　いったい、何がどうなっている……？","ENG":"I'm a Corrupted Object? But how?","TWN":"我是侵蝕體？這到底是……？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"도플갱어가 발생할 무렵부터 류드밀라는 심각한 침식 증후군에 시달리고 있었을 거야.","JPN":"ドッペルゲンガーが発生した頃から、\\nリュドミラは深刻な侵食症候群に苛まれていたはずよ。","ENG":"Lyudmila must have been experiencing severe Corruption syndrome by the time the Doppelgangers began to form.","TWN":"二重身發生的時候，盧德米拉應該正受到嚴重的侵蝕症候群折磨。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 시간이 더 흐른 어느 시점에, 본래의 류드밀라는 영원히 사라졌겠지.","JPN":"そしてさらに時が経ち、ある時点で本来のリュドミラは\\n永遠に消失してしまったはず。","ENG":"And at some point in time, the original Lyudmila probably vanished forever.","TWN":"然後隨著時間流逝，在某個時候，原本的盧德米拉就永遠消失了。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 자신의 도플갱어에게 공격을 받는 특수한 상황에서, 넌 그림자로 완전히 각성하지 못하고 자기가 인간이라고 착각한 채 지내 온 거야.","JPN":"しかし自分のドッペルゲンガーから攻撃される特殊な状況下で、\\nあなたはシャドウとして完全に覚醒することができず、\\n自らを人間だと思い込んだまま過ごしてきたの。","ENG":"But under the special circumstance of getting attacked by your Doppelganger, you mistook yourself as the original human, instead of embracing your true identity as Lyudmila's Shadow.","TWN":"但在被自己的二重身攻擊的特殊情況下，妳沒有完全覺醒成暗影，反而以為自己是人類，一直活到現在。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그러고 보니...... 그 녀석이 했던 말......","JPN":"そういえば……あいつが言った言葉……","ENG":"Come to think of it... The words he said...","TWN":"這麼說來……那傢伙說的話是……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"큭...... 크큭......","JPN":"クッ……ククッ……","ENG":"Hah... Hah hah...","TWN":"呵……呵呵……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"혼자만 고고한 척 하기는......","JPN":"自分だけ高尚ぶりやがって……","ENG":"Look at you, pretending to be all noble...","TWN":"裝什麼清高……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_CORRUPT","text":{"KOREA":"어차피 우리와 별반 다를 것도 없는 주제에...... 구역질나는군......","JPN":"どうせ俺らと大差ないくせして……反吐が出るぜ……","ENG":"You're no different from us... You make me vomit...","TWN":"妳和我們又沒什麼不同……真令人噁心……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THMEA_SAD_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_CORRUPT","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그 말이...... 그런 뜻이었나......?","JPN":"あれは……そういう意味だったのか……？","ENG":"Is that... what he meant?","TWN":"那些話……原來是這個意思……？"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자신의 처지를 납득한 것 같군. 그림자.","JPN":"自らの境遇に納得したみたいね。シャドウ。","ENG":"Looks like you've finally come to accept your situation, Shadow.","TWN":"妳了解自己的處境了吧，暗影。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네 안에 아직 류드밀라의 일부가 남아 있다는 건 나도 인정해.","JPN":"あなたの中にまだリュドミラの一部が残っていることは私も認めるわ。","ENG":"I'll admit that there's still some part of Lyudmila inside you.","TWN":"我承認妳裡面，還殘留著盧德米拉的一部分。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 그녀의 동료이자 친우로서, 내 손으로 직접 널 매장해 주겠어.","JPN":"だから彼女の仲間として、そして親友として、この手であなたを葬ってあげる。","ENG":"So as her colleague and friend, I will personally put you down.","TWN":"所以作為她的夥伴和朋友，我會親手埋葬妳。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"순순히 죽든, 저항하든 뭐라도 좋아.","JPN":"大人しく死ぬのも抵抗するのもあなたの自由よ。","ENG":"It's up to you whether you want to accept the execution or resist.","TWN":"乖乖去死也好，拼命抵抗也罷，妳要怎麼樣都行。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"적어도 지금까지 그녀의 의지를 이어 준 것을 존중해서, 네가 원하는 대로 상대해 주지.","JPN":"今まで彼女の意志を継いでくれたことに敬意を表し、せめてあなたの望むとおりに相手をしてあげるわ。","ENG":"Since you've continued her legacy for so long, I'll let you choose how you want it to end.","TWN":"至少，我對妳一直以來繼承她的意志表示尊敬。妳想怎麼樣，我都會奉陪到底的。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하하...... 하하하......","JPN":"ハハ……ハハハ……","ENG":"Hah hah... Hah hah hah...","TWN":"哈哈……哈哈哈……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"조금은 성장했다고 생각했는데...... 나는 여전히 얼빠진 채였군.","JPN":"少しは成長したと思っていたが……私は今でも\\n間抜けのままだったか。","ENG":"I thought I had matured a little... But it turns out I've been a fool, as always.","TWN":"我還以為自己有點成長了……結果還是一樣笨拙啊。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"바보처럼 아무것도 모르고...... 지금까지 뭘 해 온 거지......","JPN":"馬鹿みたいに何も知らないで……今まで何をしてきたんだ……","ENG":"How could I not notice it at all? What have I been doing all along?","TWN":"像個笨蛋一樣一無所知……我至今為止都在幹什麼啊……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......이수연.","JPN":"……カナミ。","ENG":"Sooyeon.","TWN":"……李秀妍。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"듣고 있어.","JPN":"ええ。","ENG":"I'm listening.","TWN":"我在聽。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"나는 전대장으로서 대원들을 지키기 위해, 그리고 세계를 지키기 위해 평생을 싸웠다.","JPN":"私は戦隊長として隊員たちを守るべく、そして世界を\\n守るべく今まで戦ってきた。","ENG":"I fought all my life to protect my troops and the world.","TWN":"身為戰隊隊長，我一生都在為了保護隊員，還有保護世界而戰。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"비록 그 모든 것들이 거짓이었다고 해도, 전대장으로서의 긍지만큼은 버리지 않겠어.","JPN":"たとえそれがすべて偽りだったとしても、戦隊長としての誇りを\\n捨てるつもりはない。","ENG":"Even if that all turned out to be a lie, I won't forfeit my pride as their Commander.","TWN":"即使這一切都是假的，我也不會捨棄身為戰隊隊長的驕傲。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내가 대원들에게 위험 요소가 된다면......","JPN":"私が隊員たちにとって危険要素となるなら……","ENG":"If I'm going to be a threat to my troops...","TWN":"如果我的存在會給隊員們帶來危險……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"차라리 그 전에...... 날 죽여다오.","JPN":"そうなる前にいっそのこと……私を殺してくれ。","ENG":"Please kill me... before it comes to that.","TWN":"那不如就在那之前……殺了我吧。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알겠다. 그게 네 선택이라면.","JPN":"わかったわ。それがあなたの選択なら。","ENG":"Understood. If that's what you wish.","TWN":"知道了，如果這就是妳的選擇的話。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"잘 가라.","JPN":"せめて安らかに。","ENG":"Farewell.","TWN":"再見了。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L16_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_QM","text":{"KOREA":"그만두시죠, 이수연님.","JPN":"おやめください、カナミ・キズナ殿。","ENG":"That's enough, ma'am.","TWN":"請住手，李秀妍小姐。"},"stage":{"bg":"CORRIDOR","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"}]`);export{e as default};